// Package fuzzy provides fuzzy string matching utilities.
package fuzzy

import "strings"

// Match checks if the pattern matches the text using fuzzy matching.
// Each character in the pattern must appear in the text in order,
// but not necessarily consecutively. Matching is case-insensitive.
func Match(text, pattern string) bool {
	if pattern == "" {
		return true
	}

	textRunes := []rune(strings.ToLower(text))
	patternRunes := []rune(pattern)
	patternIdx := 0

	for _, tr := range textRunes {
		if patternIdx >= len(patternRunes) {
			break
		}
		if tr == patternRunes[patternIdx] {
			patternIdx++
		}
	}

	return patternIdx == len(patternRunes)
}

package fuzzy

import "testing"

func TestMatch(t *testing.T) {
	tests := []struct {
		name    string
		text    string
		pattern string
		want    bool
	}{
		{
			name:    "exact match",
			text:    "hello",
			pattern: "hello",
			want:    true,
		},
		{
			name:    "case insensitive",
			text:    "Hello",
			pattern: "hello",
			want:    true,
		},
		{
			name:    "substring match",
			text:    "hello-world",
			pattern: "world",
			want:    true,
		},
		{
			name:    "no match",
			text:    "hello",
			pattern: "xyz",
			want:    false,
		},
		{
			name:    "empty pattern matches all",
			text:    "hello",
			pattern: "",
			want:    true,
		},
		{
			name:    "empty text with pattern",
			text:    "",
			pattern: "hello",
			want:    false,
		},
		{
			name:    "both empty",
			text:    "",
			pattern: "",
			want:    true,
		},
		{
			name:    "fuzzy match with separator",
			text:    "nikbrunner/imf-notes",
			pattern: "imfnotes",
			want:    true,
		},
		{
			name:    "fuzzy match abbreviated",
			text:    "hello-world",
			pattern: "hw",
			want:    true,
		},
		{
			name:    "fuzzy match out of order",
			text:    "acb",
			pattern: "abc",
			want:    false,
		},
		{
			name:    "fuzzy match case insensitive with gaps",
			text:    "Black-Atom-Industries",
			pattern: "bai",
			want:    true,
		},
		{
			name:    "fuzzy match with repeated characters",
			text:    "banana",
			pattern: "bnn",
			want:    true,
		},
		{
			name:    "fuzzy match unicode text",
			text:    "日本語テキスト",
			pattern: "日本",
			want:    true,
		},
		{
			name:    "fuzzy match unicode pattern with gaps",
			text:    "日本語テキスト",
			pattern: "日テ",
			want:    true,
		},
		{
			name:    "fuzzy match pattern longer than text",
			text:    "hi",
			pattern: "hello",
			want:    false,
		},
		{
			name:    "fuzzy match single character",
			text:    "hello",
			pattern: "e",
			want:    true,
		},
		{
			name:    "fuzzy match single character not found",
			text:    "hello",
			pattern: "z",
			want:    false,
		},
		{
			name:    "fuzzy match with numbers",
			text:    "helm-2.0-release",
			pattern: "h20r",
			want:    true,
		},
		{
			name:    "fuzzy match with spaces",
			text:    "my session name",
			pattern: "msn",
			want:    true,
		},
		{
			name:    "fuzzy match underscores",
			text:    "some_test_file.go",
			pattern: "stfg",
			want:    true,
		},
		{
			name:    "fuzzy match mixed case",
			text:    "GitHubActions",
			pattern: "gha",
			want:    true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := Match(tt.text, tt.pattern)
			if got != tt.want {
				t.Errorf("Match(%q, %q) = %v, want %v", tt.text, tt.pattern, got, tt.want)
			}
		})
	}
}

func BenchmarkMatch(b *testing.B) {
	text := "nikbrunner/imf-notes"
	pattern := "imfnotes"

	for i := 0; i < b.N; i++ {
		Match(text, pattern)
	}
}

func BenchmarkMatchLongText(b *testing.B) {
	text := "github.com/black-atom-industries/helm/internal/lib/fuzzy/fuzzy.go"
	pattern := "gibailifugo"

	for i := 0; i < b.N; i++ {
		Match(text, pattern)
	}
}

