package model

import (
	"testing"

	"github.com/black-atom-industries/helm/internal/config"
	"github.com/black-atom-industries/helm/internal/tmux"
)

func TestFuzzyMatch(t *testing.T) {
	tests := []struct {
		name    string
		text    string
		pattern string
		want    bool
	}{
		{
			name:    "exact match",
			text:    "hello",
			pattern: "hello",
			want:    true,
		},
		{
			name:    "case insensitive",
			text:    "Hello",
			pattern: "hello",
			want:    true,
		},
		{
			name:    "substring match",
			text:    "hello-world",
			pattern: "world",
			want:    true,
		},
		{
			name:    "no match",
			text:    "hello",
			pattern: "xyz",
			want:    false,
		},
		{
			name:    "empty pattern matches all",
			text:    "hello",
			pattern: "",
			want:    true,
		},
		{
			name:    "empty text with pattern",
			text:    "",
			pattern: "hello",
			want:    false,
		},
		{
			name:    "both empty",
			text:    "",
			pattern: "",
			want:    true,
		},
		{
			name:    "fuzzy match with separator",
			text:    "nikbrunner/imf-notes",
			pattern: "imfnotes",
			want:    true,
		},
		{
			name:    "fuzzy match abbreviated",
			text:    "hello-world",
			pattern: "hw",
			want:    true,
		},
		{
			name:    "fuzzy match out of order",
			text:    "acb",
			pattern: "abc",
			want:    false,
		},
		{
			name:    "fuzzy match case insensitive with gaps",
			text:    "Black-Atom-Industries",
			pattern: "bai",
			want:    true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := fuzzyMatch(tt.text, tt.pattern)
			if got != tt.want {
				t.Errorf("fuzzyMatch(%q, %q) = %v, want %v", tt.text, tt.pattern, got, tt.want)
			}
		})
	}
}

func TestIsCursorValid(t *testing.T) {
	m := Model{
		items: []Item{
			{Type: ItemTypeSession, SessionIndex: 0},
			{Type: ItemTypeSession, SessionIndex: 1},
			{Type: ItemTypeSession, SessionIndex: 2},
		},
	}

	tests := []struct {
		name   string
		cursor int
		want   bool
	}{
		{name: "valid first", cursor: 0, want: true},
		{name: "valid middle", cursor: 1, want: true},
		{name: "valid last", cursor: 2, want: true},
		{name: "negative", cursor: -1, want: false},
		{name: "out of bounds", cursor: 3, want: false},
		{name: "way out of bounds", cursor: 100, want: false},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			m.cursor = tt.cursor
			got := m.isCursorValid()
			if got != tt.want {
				t.Errorf("isCursorValid() with cursor=%d = %v, want %v", tt.cursor, got, tt.want)
			}
		})
	}
}

